impl TryFrom<u32> for ItemCode {
    type Error = InvalidItemCode;

    fn try_from(value: u32) -> Result<Self, Self::Error> {
        let ty = value & ItemCode::TYPE_MASK;
        let variant = ((value & ItemCode::VAR_MASK) >> 8) as u8;
        if !ItemCode::is_defined(ty, variant) {
            return Err(InvalidItemCode(value));
        }
        Ok(ItemCode(value))
    }
}
